clear alllam=780e-9:1e-9:820e-9; lam_nm=lam*1e9; [crap,ind1]=min(abs(lam_nm-800));a1_deg=50; a1=a1_deg*pi/180; % angle of incidentgroove_den1=1480; % grooves per mmd1=1e-3/groove_den1;b1=asin( sin(a1)-lam/d1  ); % beta as a function of lambdab1_deg = b1*180/pi;delta_groove=1; relative_angle_deg=0.0835;      % scenario 1%delta_groove=1; relative_angle_deg=0.084;      % scenario 2relative_angle=relative_angle_deg*pi/180;a2=-b1-relative_angle;a2_deg = a2*180/pi;groove_den2=1480+delta_groove; % grooves per mmd2=1e-3/groove_den2;b2=asin( sin(a2)-lam/d2  );b2_deg = b2*180/pi;retro_angle_deg = 0.14795;%offset_angle_mid=(-b2)-a1+relative_angle;offset_angle_deg = -b2_deg-50;  % off-axis angle (51->49)a3_deg = 50 - offset_angle_deg + relative_angle_deg + 2*retro_angle_deg;%offset_angle_mid = 0;%a3=(-b2)-2*offset_angle_mid;a3 = a3_deg*pi/180;b3=asin( sin(a3)-lam/d2  );b3_deg = b3*180/pi;a4=-b3+relative_angle;a4_deg = a4*180/pi;b4=asin( sin(a4)-lam/d1  );b4_deg = b4*180/pi;offset_angle_final=-b4-a1;chrp = abs(1e6*(b4(11)-b4(31))/20);  % chirp: urad/nm%%figure(1);set(gcf,'color',[1 1 1])set(gca,'fontsize',14)%plot(lam_nm,1e6*(offset_angle_final-offset_angle_final(ind1)),'-r','LineWidth',1)plot(lam_nm,1e6*(b4+50*pi/180),'-r','LineWidth',1)xlabel('Wavelength [nm]','fontsize',18)ylabel('Angle deviation from 800nm [micro-rad]','fontsize',18)title([num2str(chrp),' urad/nm per 1 gr/mm offset'],'fontsize',18)%%figure(2)subplot(2,4,5)plot(lam*1e9,b1_deg)title('beta1')subplot(2,4,2)plot(lam*1e9,a2_deg)title('alpha2')subplot(2,4,6)plot(lam*1e9,b2_deg)title('beta2')subplot(2,4,3)plot(lam*1e9,a3_deg)title('alpha3')subplot(2,4,7)plot(lam*1e9,b3_deg)title('beta3')subplot(2,4,4)plot(lam*1e9,a4_deg)title('alpha3')subplot(2,4,8)plot(lam*1e9,b4_deg+50)title('beta4 [deg]')
